SELECT comment_id
FROM moderation_logs
WHERE review_duration > 0;

SELECT action 
FROM moderation_logs 
WHERE comment_id = 1 AND moderator_id = 0;

SELECT action 
FROM moderation_logs 
WHERE is_flagged = 1 OR reviewed_by_admin = 0;

SELECT COUNT(*) AS approved_comments
FROM comments
WHERE moderation_status = 'approved';
